import { useState } from 'react';
import './Projects.css';

const Projects = () => {
  const [filter, setFilter] = useState('All');
  const [selectedProject, setSelectedProject] = useState(null);

  const projects = [
    {
      id: 4,
      title: "Term Sheet AI",
      description: "AI-powered legal document analysis platform achieving 95% efficiency improvement in term sheet processing and analysis.",
      brief: "Built a comprehensive legal document analysis system with advanced NLP capabilities to automate term sheet processing, reducing manual review time by 95% and improving accuracy in contract extraction.",
      technologies: ["Python", "AI/ML", "NLP", "Legal Tech"],
      image: "/term_sheet-ai.jpg",
      category: "AI/ML",
      link: "#",
      github: "https://github.com/TRIDENT11107/TermSheet-AI",
      features: [
        "95% efficiency improvement",
        "Legal document analysis",
        "AI-powered processing",
        "Automated term extraction"
      ]
    },
    {
      id: 1,
      title: "MediTrust AI",
      description: "Automated PII detection and redaction for clinical documents — enables HIPAA-compliant document anonymization with a no-data-retention live demo.",
      brief: "Comprehensive PII detection and automated redaction system for clinical documents with HIPAA-compliant processing. Features real-time detection, zero data retention, and production-ready deployment.",
      technologies: ["Python", "NLP", "OCR", "Computer Vision", "FAISS"],
      image: "/meditrust_img.jpg",
      category: "AI/ML",
      link: "#",
      github: "#",
      features: [
        "PII detection and automated redaction",
        "HIPAA-compliant processing with no data retention",
        "Live demo uploader for PDF/JPG/PNG",
        "Fast processing optimized for production deployment"
      ]
    },
    {
      id: 2,
      title: "Blogging Platform",
      description: "Designed and developed comprehensive blogging platform with complete content management, secure authentication, and responsive user interfaces.",
      brief: "Full-stack blogging platform featuring RESTful APIs, MongoDB backend, JWT authentication, and a responsive React frontend. Includes rich text editor, user management, and comments system.",
      technologies: ["React", "Node.js", "Express.js", "MongoDB"],
      image: "https://images.unsplash.com/photo-1551288049-bebda4e38f71?ixlib=rb-4.0.3&ixid=M3wxMJA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80",
      category: "Web Development",
      link: "#",
      github: "#",
      features: [
        "Complete content management",
        "Secure authentication systems",
        "Responsive design",
        "RESTful API implementation"
      ]
    },
    {
      id: 3,
      title: "Day Planner Website",
      description: "Built intuitive day planner website with responsive, user-friendly interfaces and optimal performance for daily task management.",
      brief: "Interactive task management application with real-time updates, local storage persistence, and intuitive drag-and-drop interface for efficient daily planning.",
      technologies: ["React", "JavaScript", "HTML", "CSS"],
      image: "https://images.unsplash.com/photo-1486312338219-ce68d2c6f44d?ixlib=rb-4.0.3&ixid=M3wxMJA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80",
      category: "Web Development",
      link: "#",
      github: "#",
      features: [
        "Intuitive user interface",
        "Daily task management",
        "Responsive design",
        "Performance optimization"
      ]
    }
  ];

  const categories = ['All', 'AI/ML', 'Web Development'];

  const filteredProjects = filter === 'All' 
    ? projects 
    : projects.filter(project => project.category === filter);

  const stats = [
    { number: "95%", label: "Efficiency Improvement", subtitle: "Term Sheet AI Impact" },
    { number: "<1s", label: "Image Search Speed", subtitle: "ProcMart Innovation" },
    { number: "6+", label: "Projects Built", subtitle: "Real-world Applications" },
    { number: "15+", label: "Technologies Used", subtitle: "Diverse Tech Stack" }
  ];

  return (
    <section id="projects" className="section projects">
      <div className="container">
        <h2 className="section-title">Featured Projects</h2>
        <p className="section-subtitle">
          Real-world applications showcasing AI/ML innovation, full-stack development, and 
          creative problem-solving across different domains.
        </p>

        <div className="project-filters">
          {categories.map((category) => (
            <button
              key={category}
              className={`filter-btn ${filter === category ? 'active' : ''}`}
              onClick={() => setFilter(category)}
            >
              {category}
            </button>
          ))}
        </div>

        <div className="projects-grid">
          {filteredProjects.map((project) => (
            <div 
              key={project.id} 
              className="project-card"
              onClick={() => setSelectedProject(project)}
            >
              <div className="project-image">
                <img
                  src={project.image}
                  alt={project.title}
                  onError={(e) => {
                    const img = e.currentTarget;
                    if (img.alt === 'Term Sheet AI') {
                      if (img.src.includes('term_sheet-ai.jpg')) {
                        img.src = '/term_sheet_ai_results.png';
                        return;
                      }
                      if (img.src.includes('term_sheet_ai_results.png')) {
                        img.src = '/term_sheet_ai.png';
                        return;
                      }
                    }
                    img.onerror = null;
                    img.src = 'https://images.unsplash.com/photo-1522869635100-9f4c5e86aa37?auto=format&fit=crop&w=1000&q=80';
                  }}
                />
                <div className="project-category-badge">{project.category}</div>
              </div>
              
              <div className="project-content">
                <h3 className="project-title">{project.title}</h3>
                <p className="project-description">{project.description}</p>
              </div>
            </div>
          ))}
        </div>

        <div className="project-stats">
          {stats.map((stat, index) => (
            <div key={index} className="stat-card">
              <div className="stat-number">{stat.number}</div>
              <div className="stat-label">{stat.label}</div>
              <div className="stat-subtitle">{stat.subtitle}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Project Detail Modal */}
      {selectedProject && (
        <div className="project-modal-overlay" onClick={() => setSelectedProject(null)}>
          <div className="project-modal" onClick={(e) => e.stopPropagation()}>
            <button 
              className="modal-close"
              onClick={() => setSelectedProject(null)}
            >
              ✕
            </button>
            
            <a 
              href={selectedProject.github} 
              className="modal-github-link"
              target="_blank"
              rel="noopener noreferrer"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M15 22v-4a4.8 4.8 0 0 0-1-3.5c3 0 6-2 6-5.5.08-1.25-.27-2.48-1-3.5.28-1.15.28-2.35 0-3.5 0 0-1 0-3 1.5-2.64-.5-5.36-.5-8 0C6 2 5 2 5 2c-.3 1.15-.3 2.35 0 3.5A5.403 5.403 0 0 0 4 9c0 3.5 3 5.5 6 5.5-.39.49-.68 1.05-.85 1.65-.17.6-.22 1.23-.15 1.85v4"></path>
                <path d="M9 18c-4.51 2-5-2-7-2"></path>
              </svg>
            </a>

            <div className="modal-header">
              <div className="modal-header-line"></div>
              <span className="modal-header-text">PROJECT OVERVIEW</span>
            </div>

            <h1 className="modal-title">{selectedProject.title}</h1>

            <div className="modal-content">
              <div className="modal-left">
                <div className="modal-section">
                  <h3 className="modal-section-title">01 // BRIEF</h3>
                  <p className="modal-section-content">{selectedProject.brief}</p>
                </div>

                <div className="modal-section">
                  <h3 className="modal-section-title">02 // KEY FEATURES</h3>
                  <ul className="modal-features">
                    {selectedProject.features.map((feature, index) => (
                      <li key={index}>{feature}</li>
                    ))}
                  </ul>
                </div>
              </div>

              <div className="modal-right">
                <div className="modal-tech-stack">
                  <h3 className="modal-tech-title">– SYSTEM_STACK</h3>
                  <div className="modal-tech-grid">
                    {selectedProject.technologies.map((tech, index) => (
                      <div key={index} className="modal-tech-item">{tech}</div>
                    ))}
                  </div>
                </div>

                <div className="modal-actions">
                  <a href={selectedProject.github} className="modal-btn modal-btn-primary" target="_blank" rel="noopener noreferrer">
                    View Code
                  </a>
                  <a href={selectedProject.link} className="modal-btn modal-btn-secondary">
                    Live Demo
                  </a>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

export default Projects;
